class Solution {
    public int countPairs(int[] nums, int low, int high) {
        Trie trie = new Trie();
        int res = 0;
        for (int num : nums) {
            res += trie.query(num, high) - trie.query(num, low - 1);
            trie.insert(num);
        }
        return res;
    }
}

class Trie {
    Trie[] children = new Trie[2];
    int count = 0;

    void insert(int num) {
        Trie node = this;
        for (int i = 15; i >= 0; i--) {
            int bit = (num >> i) & 1;
            if (node.children[bit] == null) {
                node.children[bit] = new Trie();
            }
            node = node.children[bit];
            node.count++;
        }
    }

    int query(int num, int x) {
        Trie node = this;
        int res = 0;
        for (int i = 15; i >= 0; i--) {
            int bit = (num >> i) & 1;
            if (((x >> i) & 1) != bit) {
                if (node.children[bit] != null) {
                    res += node.children[bit].count;
                }
                node = node.children[1 - bit] != null ? node.children[1 - bit] : node.children[bit];
            } else {
                node = node.children[bit] != null ? node.children[bit] : node.children[1 - bit];
            }
        }
        return res;
    }
}
